import{_ as t,o as r,c as e,ag as n}from"./chunks/framework.D9bIGSBm.js";const h=JSON.parse('{"title":"故障排查","description":"","frontmatter":{},"headers":[],"relativePath":"reference/troubleshooting.md","filePath":"reference/troubleshooting.md"}'),s={name:"reference/troubleshooting.md"};function l(a,o,g,i,p,d){return r(),e("div",null,[...o[0]||(o[0]=[n('<h1 id="故障排查" tabindex="-1">故障排查 <a class="header-anchor" href="#故障排查" aria-label="Permalink to &quot;故障排查&quot;">​</a></h1><p>本页收录常见故障的现象、原因与解决步骤。如果问题不在此列，建议先查看 <a href="/docs/reference/faq.html">常见问题</a>，或尝试重启应用。</p><hr><h2 id="cli-未被识别-任务无法启动" tabindex="-1">CLI 未被识别 / 任务无法启动 <a class="header-anchor" href="#cli-未被识别-任务无法启动" aria-label="Permalink to &quot;CLI 未被识别 / 任务无法启动&quot;">​</a></h2><p><strong>现象：</strong> 新建任务后任务立即报错，提示找不到 <code>claude</code>、<code>codex</code> 或 <code>opencode</code> 命令；或依赖管理页面显示 CLI 未安装。</p><p><strong>原因：</strong> LoongCode 在启动时通过系统 PATH 自动发现 CLI 可执行文件。若 CLI 未安装、安装在非标准路径，或安装后应用未重启，均会导致无法识别。</p><p><strong>解决步骤：</strong></p><ol><li><p><strong>检查 PATH 中是否有 CLI：</strong> 打开系统终端，输入 <code>claude --version</code>（或 <code>codex --version</code> / <code>opencode --version</code>），若提示&quot;命令未找到&quot;则说明未正确安装或路径未加入 PATH。</p></li><li><p><strong>通过依赖管理安装：</strong> 前往<strong>设置 → 依赖管理</strong>，查看 Claude / Codex / OpenCode CLI 的状态（三者「至少装一个」即可）；若显示未安装，点击<strong>安装</strong>按钮，等待安装完成后<strong>重启应用</strong>。</p></li><li><p><strong>手动指定 CLI 路径：</strong> 若 CLI 已安装但路径非标准，前往<strong>设置 → 常规 → CLI 命令</strong>，在对应输入框中填写可执行文件的绝对路径（如 <code>/usr/local/bin/claude</code>），或点击&quot;选择文件&quot;定位。</p></li><li><p><strong>切换安装来源：</strong> 若安装过程中网络下载失败，可在<strong>设置 → 依赖管理 → 安装来源</strong>切换到其他来源（官方脚本 / GitHub 直连 / GitHub 加速），或配置自定义镜像前缀后重试。</p></li></ol><blockquote><p>首次安装指引请参阅 <a href="/docs/guide/prerequisites.html">前置依赖</a>。</p></blockquote><hr><h2 id="任务报错或卡住" tabindex="-1">任务报错或卡住 <a class="header-anchor" href="#任务报错或卡住" aria-label="Permalink to &quot;任务报错或卡住&quot;">​</a></h2><p><strong>现象：</strong> 任务运行中突然停止、长时间无响应，或对话面板显示错误信息。</p><p><strong>原因：</strong> 常见原因包括：网络中断、API 服务不可用、对话上下文超出模型限制、CLI 进程意外退出等。</p><p><strong>解决步骤：</strong></p><ol><li><p><strong>停止并重试：</strong> 点击对话输入区的<strong>停止</strong>按钮结束当前回合，然后重新发送一条消息继续任务。</p></li><li><p><strong>上下文超限：</strong> 若错误信息包含&quot;context length&quot;或&quot;token limit&quot;等关键词，说明上下文已满。自 v0.3.1 起支持自动恢复超限错误；若未自动恢复，可在对话面板底部手动点击<strong>压缩</strong>按钮执行摘要压缩后继续。开启<strong>设置 → 常规 → 自动压缩</strong>可避免此类中断。</p></li><li><p><strong>查看错误信息：</strong> 对话面板会保留完整的错误详情。根据提示内容判断是 API Key 失效、网络问题还是其他原因，对症处理。</p></li><li><p><strong>检查网络：</strong> 若错误持续，尝试在<strong>设置 → 常规 → 网络代理</strong>中配置或移除代理，确认网络可正常访问 CLI 所需服务。</p></li></ol><hr><h2 id="更新失败" tabindex="-1">更新失败 <a class="header-anchor" href="#更新失败" aria-label="Permalink to &quot;更新失败&quot;">​</a></h2><p><strong>现象：</strong> 点击右上角更新徽标后，更新进度卡住或提示更新失败。</p><p><strong>原因：</strong> Windows 自动更新依赖网络下载完整安装包，网络不稳定时可能失败。macOS 当前不提供应用内自动更新（以官方发布说明为准），需手动操作。</p><p><strong>解决步骤：</strong></p><ol><li><p><strong>手动下载安装包：</strong> 访问 <a href="https://github.com/LoongCode0/loongcode-release/releases/latest" target="_blank" rel="noreferrer">GitHub Releases（LoongCode0/loongcode-release）</a> 下载对应平台的最新安装包：</p><ul><li>Windows：<code>.exe</code> 或 <code>.msi</code> 安装包</li><li>macOS：<code>.dmg</code> 文件</li></ul></li><li><p><strong>覆盖安装：</strong> 运行下载的安装包，直接覆盖当前版本完成升级（无需提前卸载旧版本）。</p></li><li><p><strong>macOS 用户：</strong> 应用不提供应用内更新，请按上述方式手动下载 <code>.dmg</code> 升级。若提示「无法验证开发者」，参见 <a href="/docs/reference/faq.html#macos-提示无法验证开发者怎么办">常见问题 — macOS 无法验证开发者</a> 处理后再启动。</p></li></ol><hr><h2 id="windows-下界面冻结卡死" tabindex="-1">Windows 下界面冻结卡死 <a class="header-anchor" href="#windows-下界面冻结卡死" aria-label="Permalink to &quot;Windows 下界面冻结卡死&quot;">​</a></h2><p><strong>现象：</strong> 在 Windows 上应用界面完全冻结、无法操作，严重时只能从任务管理器结束进程。</p><p><strong>原因：</strong> 旧版本存在两类已知的冻死问题，分别在不同版本中修复：</p><ol><li><strong>窗口切走 / 最小化后切回时硬冻死</strong> —— 由主 WebView 遮挡计算与内嵌浏览器轮询的同步死锁引起，<strong>v0.6.1 已修复</strong>。</li><li><strong>搜狗等中文输入法环境下，配合切窗 / 最小化恢复时偶发硬冻死</strong> —— 由底层窗口库的键盘处理被输入法同步消息重入导致的死锁引起，<strong>v0.7.0 已修复</strong>。</li></ol><p><strong>解决方法：</strong> 升级到 v0.7.0 或更高版本即可同时规避以上两类问题。按照上方「更新失败」章节的步骤下载并安装最新版本即可。</p><hr><h2 id="依赖安装失败" tabindex="-1">依赖安装失败 <a class="header-anchor" href="#依赖安装失败" aria-label="Permalink to &quot;依赖安装失败&quot;">​</a></h2><p><strong>现象：</strong> 在依赖管理页面点击安装后，进度日志显示&quot;失败&quot;；或安装完成后依赖仍显示未安装。</p><p><strong>原因：</strong> 常见原因包括网络下载失败（国内访问 GitHub 不稳定）、安装脚本执行权限不足、磁盘空间不足等。</p><p><strong>解决步骤：</strong></p><ol><li><p><strong>查看失败日志：</strong> 安装失败的日志会保留在依赖管理页面下方（离开页面再返回仍可查看）。根据错误信息判断具体原因。</p></li><li><p><strong>切换安装来源：</strong> 前往<strong>设置 → 依赖管理 → 安装来源</strong>，尝试切换到其他选项：</p><ul><li><strong>官方脚本：</strong> 使用 CLI 官方安装脚本</li><li><strong>GitHub 直连：</strong> 直接从 GitHub 下载</li><li><strong>GitHub 加速：</strong> 通过加速镜像下载（国内推荐）</li><li>也可填写<strong>自定义镜像前缀</strong>，使用私有镜像源</li></ul></li><li><p><strong>配置下载代理：</strong> 若所在网络需要代理才能访问外部资源，在<strong>设置 → 依赖管理</strong>的下载代理配置中填写代理地址，然后重试安装。</p></li><li><p><strong>点击重试：</strong> 修改来源或代理配置后，点击日志区域下方的<strong>重试</strong>按钮重新安装。</p></li></ol><hr><h2 id="网络问题" tabindex="-1">网络问题 <a class="header-anchor" href="#网络问题" aria-label="Permalink to &quot;网络问题&quot;">​</a></h2><p><strong>现象：</strong> 任务调用 AI 服务持续超时；依赖下载失败；API 请求报网络错误。</p><p><strong>原因：</strong> 应用发出的所有网络请求（包括 CLI 调用与依赖下载）都受系统网络环境影响。若所在网络需要代理访问外部服务，需要在应用内配置代理。</p><p><strong>解决步骤：</strong></p><ol><li><p><strong>配置全局网络代理：</strong> 前往<strong>设置 → 常规 → 网络代理</strong>，填写代理服务器地址（格式：<code>http://host:port</code>）。可按需填写&quot;忽略代理的地址&quot;（如 <code>localhost,127.0.0.1</code>）和自定义 CA 证书文件（企业内网场景）。</p></li><li><p><strong>配置依赖下载代理：</strong> 依赖安装的网络请求在<strong>设置 → 依赖管理</strong>的下载代理选项中单独配置，与全局代理独立。</p></li><li><p><strong>测试连通性：</strong> 配置代理后，新建一个简单任务（如发送&quot;你好&quot;）测试是否能正常得到 AI 响应。</p></li><li><p><strong>检查 API Key：</strong> 若代理已正常但请求仍失败，确认<strong>设置 → 常规 → 环境变量</strong>中的 API Key 等凭据配置正确。</p></li></ol><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/guide/quick-start.html">快速上手</a> — 回到基础操作指引</li><li><a href="/docs/reference/shortcuts.html">快捷键一览</a> — 常用快捷键速查</li><li><a href="/docs/reference/faq.html">常见问题</a> — 使用中的高频疑问</li></ul>',42)])])}const u=t(s,[["render",l]]);export{h as __pageData,u as default};
